// Paginate through all ads from Geozo API
// /v1/advertiser/ads/all returns all ads with campaign/group info
const allAds = [];
let page = 1;
const perPage = 100;
let hasMore = true;

while (hasMore && page <= 50) {
  const resp = await this.helpers.httpRequestWithAuthentication.call(this, 'httpHeaderAuth', {
    method: 'GET',
    url: 'https://api.geozo.com/v1/advertiser/ads/all',
    qs: {
      count: perPage,
      page: page,
      'order_by[0][column]': 'id',
      'order_by[0][direction]': 'desc'
    },
    json: true
  });

  const data = resp?.data || [];
  if (data.length === 0) {
    hasMore = false;
    break;
  }

  allAds.push(...data);

  // Check pagination
  const meta = resp?.meta || {};
  if (meta.current_page && meta.last_page && meta.current_page >= meta.last_page) {
    hasMore = false;
  } else if (data.length < perPage) {
    hasMore = false;
  }
  page++;
}

// Extract unique campaigns and groups
const campaignsMap = {};
const groupsMap = {};

for (const ad of allAds) {
  // Campaign
  if (ad.campaign_id && !campaignsMap[ad.campaign_id]) {
    campaignsMap[ad.campaign_id] = {
      campaign_id: ad.campaign_id,
      name: ad.campaign_name || 'Campaign ' + ad.campaign_id,
      campaign_type_id: ad.campaign_type_id || null
    };
  }

  // Group
  if (ad.ad_group_id && !groupsMap[ad.ad_group_id]) {
    groupsMap[ad.ad_group_id] = {
      ad_group_id: ad.ad_group_id,
      campaign_id: ad.campaign_id,
      name: ad.group_ad_name || 'Group ' + ad.ad_group_id
    };
  }
}

return [{
  json: {
    ads: allAds,
    campaigns: Object.values(campaignsMap),
    groups: Object.values(groupsMap),
    total_fetched: allAds.length,
    pages_fetched: page - 1
  }
}];

const data = $input.first().json;
const campaigns = data.campaigns || [];
const groups = data.groups || [];
const ads = data.ads || [];

// Geozo status mapping
const GEOZO_STATUS = {
  1: 'processed', 2: 'moderation', 3: 'banned',
  4: 'stopped', 5: 'started', 41: 'budget_ended', 42: 'suspended'
};

// Build SQL for campaigns upsert
const campaignSqls = campaigns.map(c => {
  const name = (c.name || '').replace(/'/g, "''");
  return `INSERT INTO campaigns (campaign_id, name, campaign_type_id, synced_at)
    VALUES (${c.campaign_id}, '${name}', ${c.campaign_type_id || 'NULL'}, NOW())
    ON CONFLICT (campaign_id) DO UPDATE SET
      name = EXCLUDED.name,
      campaign_type_id = COALESCE(EXCLUDED.campaign_type_id, campaigns.campaign_type_id),
      synced_at = NOW()`;
});

// Build SQL for groups upsert
const groupSqls = groups.map(g => {
  const name = (g.name || '').replace(/'/g, "''");
  return `INSERT INTO ad_groups (ad_group_id, campaign_id, name, synced_at)
    VALUES (${g.ad_group_id}, ${g.campaign_id}, '${name}', NOW())
    ON CONFLICT (ad_group_id) DO UPDATE SET
      campaign_id = EXCLUDED.campaign_id,
      name = EXCLUDED.name,
      synced_at = NOW()`;
});

// Build SQL for ads upsert
const adSqls = ads.filter(a => a.id).map(a => {
  const title = (a.title || '').replace(/'/g, "''");
  const url = (a.url || a.original_url || '').replace(/'/g, "''");
  const shortDesc = (a.short_description || '').replace(/'/g, "''");
  const statusId = a.status_id || null;
  const status = GEOZO_STATUS[statusId] || 'unknown';

  // Get bid from bids array if available
  let bid = null;
  if (a.bids && Array.isArray(a.bids)) {
    // Get first leaf bid value
    const findBid = (obj) => {
      if (obj.bid) return parseFloat(obj.bid);
      if (obj.children) {
        for (const child of Object.values(obj.children)) {
          const b = findBid(child);
          if (b) return b;
        }
      }
      return null;
    };
    for (const b of a.bids) {
      bid = findBid(b);
      if (bid) break;
    }
  }

  // Image URLs
  const imgSquare = a.media_contents?.['1:1']?.url || a.media_contents?.original_square?.url || null;
  const imgHoriz = a.media_contents?.['16:9']?.url || a.media_contents?.original_horizontal_16x9?.url || null;

  return `INSERT INTO teasers (ad_id, ad_group_id, campaign_id, title, original_url, short_description, geozo_status_id, status, bid, image_square_path, image_horizontal_path, updated_at)
    VALUES (
      ${a.id},
      ${a.ad_group_id || 'NULL'},
      ${a.campaign_id || 'NULL'},
      '${title}',
      '${url}',
      '${shortDesc}',
      ${statusId || 'NULL'},
      '${status}',
      ${bid || 'NULL'},
      ${imgSquare ? "'" + imgSquare.replace(/'/g, "''") + "'" : 'NULL'},
      ${imgHoriz ? "'" + imgHoriz.replace(/'/g, "''") + "'" : 'NULL'},
      NOW()
    )
    ON CONFLICT (ad_id) WHERE ad_id IS NOT NULL DO UPDATE SET
      ad_group_id = EXCLUDED.ad_group_id,
      campaign_id = EXCLUDED.campaign_id,
      title = EXCLUDED.title,
      original_url = EXCLUDED.original_url,
      short_description = EXCLUDED.short_description,
      geozo_status_id = EXCLUDED.geozo_status_id,
      bid = COALESCE(EXCLUDED.bid, teasers.bid),
      image_square_path = COALESCE(EXCLUDED.image_square_path, teasers.image_square_path),
      image_horizontal_path = COALESCE(EXCLUDED.image_horizontal_path, teasers.image_horizontal_path),
      updated_at = NOW()`;
});

// Combine all SQL
const allSql = [...campaignSqls, ...groupSqls, ...adSqls];

// Update ad_groups counts
const countSql = `UPDATE ad_groups ag SET
  ad_count = (SELECT COUNT(*) FROM teasers t WHERE t.ad_group_id = ag.ad_group_id),
  ad_started_count = (SELECT COUNT(*) FROM teasers t WHERE t.ad_group_id = ag.ad_group_id AND t.geozo_status_id = 5)`;

allSql.push(countSql);

const sql = allSql.join(';\n') + ";\nSELECT 'ok' as result, " + ads.length + " as ads_synced, " + campaigns.length + " as campaigns_synced, " + groups.length + " as groups_synced";

return [{ json: { sql, stats: { ads: ads.length, campaigns: campaigns.length, groups: groups.length } } }];
